    {"id":"d001","name":"Pan-Seared Salmon with Roasted Vegetables","image":"https://www.themealdb.com/images/media/meals/pbzcrx1763765096.jpg","meal_type":"dinner","goals":["diabetes","keto","muscle","maintain"],"minutes":30,"servings":2,"tags":["omega-3","high-protein","low-carb"],"ingredients":[{"name":"Salmon fillets","amount":"2 x 150g"},{"name":"Broccoli florets","amount":"200g"},{"name":"Cherry tomatoes","amount":"150g"},{"name":"Asparagus","amount":"150g"},{"name":"Olive oil","amount":"2 tbsp"},{"name":"Lemon","amount":"1"},{"name":"Garlic","amount":"2 cloves"},{"name":"Fresh thyme","amount":"few sprigs"}],"steps":["Preheat oven to 200C. Toss vegetables with 1 tbsp oil, garlic, thyme. Roast 20 min.","Pat salmon dry, season with salt and pepper.","Heat remaining oil in a pan. Sear salmon skin-side down 4 min.","Flip, cook 2 more minutes.","Squeeze lemon over salmon, serve with roasted veg."],"source":"Curated","calories":420,"protein_g":38,"carbs_g":12,"fat_g":25,"fiber_g":5,"sugar_g":5},
    {"id":"d002","name":"Chicken Thigh with Ratatouille","image":"https://www.themealdb.com/images/media/meals/wrpwuu1511786491.jpg","meal_type":"dinner","goals":["diabetes","weight_loss","maintain"],"minutes":45,"servings":4,"tags":["french","mediterranean","low-gi"],"ingredients":[{"name":"Chicken thighs (skin-on)","amount":"4"},{"name":"Zucchini","amount":"2"},{"name":"Eggplant","amount":"1"},{"name":"Bell peppers","amount":"2"},{"name":"Onion","amount":"1"},{"name":"Canned tomatoes","amount":"400g"},{"name":"Garlic","amount":"3 cloves"},{"name":"Herbes de Provence","amount":"2 tsp"},{"name":"Olive oil","amount":"3 tbsp"}],"steps":["Season chicken with herbs. Sear skin-side down 5 min.","Flip, cook 3 min. Remove and set aside.","Dice all vegetables. Sauté onion and garlic 3 min.","Add eggplant, peppers, zucchini. Cook 5 min.","Add tomatoes. Nestle chicken in. Cover, simmer 25 min."],"source":"Curated","calories":380,"protein_g":32,"carbs_g":16,"fat_g":22,"fiber_g":6,"sugar_g":10},
    {"id":"d003","name":"Beef Stew with Root Vegetables","image":"https://www.themealdb.com/images/media/meals/svprys1511176755.jpg","meal_type":"dinner","goals":["diabetes","muscle","maintain"],"minutes":120,"servings":6,"tags":["comfort","high-protein","low-gi"],"ingredients":[{"name":"Beef chuck, cubed","amount":"800g"},{"name":"Carrots","amount":"3"},{"name":"Parsnips","amount":"2"},{"name":"Celery","amount":"2 stalks"},{"name":"Onion","amount":"2"},{"name":"Garlic","amount":"3 cloves"},{"name":"Beef stock","amount":"500ml"},{"name":"Red wine","amount":"200ml"},{"name":"Tomato paste","amount":"2 tbsp"},{"name":"Bay leaves","amount":"2"},{"name":"Thyme","amount":"3 sprigs"},{"name":"Olive oil","amount":"2 tbsp"}],"steps":["Brown beef in batches in a hot Dutch oven. Set aside.","Sauté onion, garlic 3 min. Add tomato paste.","Deglaze with red wine.","Return beef, add stock, bay leaves, thyme.","Simmer 1 hour. Add vegetables. Cook 40 min more."],"source":"Curated","calories":380,"protein_g":36,"carbs_g":18,"fat_g":16,"fiber_g":5,"sugar_g":8},
    {"id":"d004","name":"Baked Cod with Herb Crust","image":"https://www.themealdb.com/images/media/meals/vuxgtm1764112923.jpg","meal_type":"dinner","goals":["diabetes","weight_loss","maintain"],"minutes":25,"servings":2,"tags":["low-calorie","high-protein","lean"],"ingredients":[{"name":"Cod fillets","amount":"2 x 160g"},{"name":"Wholemeal breadcrumbs","amount":"30g"},{"name":"Parsley, chopped","amount":"2 tbsp"},{"name":"Lemon zest","amount":"1 lemon"},{"name":"Garlic, minced","amount":"1 clove"},{"name":"Olive oil","amount":"1 tbsp"},{"name":"Green beans","amount":"200g"},{"name":"Butter","amount":"10g"}],"steps":["Preheat oven to 200C.","Mix breadcrumbs, parsley, lemon zest, garlic and oil.","Place cod on tray, press herb crust on top.","Bake 12-15 minutes.","Blanch green beans, toss with butter. Serve with cod."],"source":"Curated","calories":290,"protein_g":36,"carbs_g":12,"fat_g":11,"fiber_g":4,"sugar_g":3},
    {"id":"d005","name":"Turkey Meatballs in Tomato Sauce","image":"https://www.themealdb.com/images/media/meals/8rfd4q1764112993.jpg","meal_type":"dinner","goals":["diabetes","weight_loss","muscle","maintain"],"minutes":35,"servings":4,"tags":["lean","high-protein","family"],"ingredients":[{"name":"Turkey mince","amount":"500g"},{"name":"Egg","amount":"1"},{"name":"Oat flour","amount":"30g"},{"name":"Garlic","amount":"2 cloves"},{"name":"Onion, grated","amount":"1/2"},{"name":"Canned tomatoes","amount":"400g"},{"name":"Basil","amount":"fresh handful"},{"name":"Olive oil","amount":"1 tbsp"},{"name":"Zucchini noodles","amount":"400g"}],"steps":["Mix turkey, egg, oat flour, garlic, onion. Form 16 balls.","Brown meatballs in olive oil, 3 min per side.","Add canned tomatoes, simmer 15 min.","Serve meatballs over zucchini noodles with basil."],"source":"Curated","calories":310,"protein_g":34,"carbs_g":14,"fat_g":13,"fiber_g":4,"sugar_g":7},
