with open("assets/recipes.json", "w") as f:
    json.dump(recipes, f, indent=2, ensure_ascii=False)

# Stats
from collections import Counter
print(f"Total: {len(recipes)}")
by_type = Counter(r["meal_type"] for r in recipes)
print(f"By type: {dict(by_type)}")
imgs = [r["image"] for r in recipes]
dupes = {k:v for k,v in Counter(imgs).items() if v > 1}
print(f"Unique images: {len(set(imgs))}/{len(imgs)}")
if dupes:
    for u,c in dupes.items():
        print(f"  {c}x {u.split('/')[-1]}")
muscle = sum(1 for r in recipes if "muscle" in r.get("goals",[]))
diabetes = sum(1 for r in recipes if "diabetes" in r.get("goals",[]))
print(f"Muscle: {muscle}, Diabetes: {diabetes}")
print(f"Snacks: {sum(1 for r in recipes if r['meal_type']=='snack')}")
print("Done!")
